-- Migration to create cadet testing system tables and insert initial question pool

CREATE TABLE t_p29017774_avn_academy_training.test_questions (
  id SERIAL PRIMARY KEY,
  subject VARCHAR(255) NOT NULL,
  type VARCHAR(50) NOT NULL CHECK (type IN ('choice', 'multichoice', 'matching', 'essay')),
  question_text TEXT NOT NULL,
  options JSONB DEFAULT NULL, -- Для choice (список строк), matching (список пар), multichoice (список строк)
  correct_answer JSONB NOT NULL, -- Ответ: строка, массив строк или объект
  explanation TEXT DEFAULT NULL,
  elo_rating INTEGER DEFAULT 1000,
  criteria_matrix JSONB DEFAULT NULL, -- Для essay вопросов
  created_at TIMESTAMP DEFAULT NOW()
);

CREATE TABLE t_p29017774_avn_academy_training.test_attempts (
  id SERIAL PRIMARY KEY,
  user_id INTEGER NOT NULL REFERENCES t_p29017774_avn_academy_training.users(id) ON DELETE CASCADE,
  status VARCHAR(50) NOT NULL DEFAULT 'in_progress' CHECK (status IN ('in_progress', 'completed', 'aborted')),
  difficulty INTEGER NOT NULL DEFAULT 5 CHECK (difficulty BETWEEN 1 AND 10),
  start_elo INTEGER NOT NULL DEFAULT 1000,
  end_elo INTEGER DEFAULT NULL,
  warnings_count INTEGER NOT NULL DEFAULT 0,
  started_at TIMESTAMP DEFAULT NOW(),
  completed_at TIMESTAMP DEFAULT NULL,
  expires_at TIMESTAMP NOT NULL
);

CREATE TABLE t_p29017774_avn_academy_training.test_answers (
  id SERIAL PRIMARY KEY,
  attempt_id INTEGER NOT NULL REFERENCES t_p29017774_avn_academy_training.test_attempts(id) ON DELETE CASCADE,
  question_id INTEGER NOT NULL REFERENCES t_p29017774_avn_academy_training.test_questions(id) ON DELETE CASCADE,
  student_answer JSONB NOT NULL,
  is_correct BOOLEAN DEFAULT NULL,
  grade NUMERIC(5,2) DEFAULT NULL, -- Итоговая оценка
  feedback TEXT DEFAULT NULL,       -- ИИ-отзыв
  criteria_evaluation JSONB DEFAULT NULL, -- Оценки по 5 критериям
  answered_at TIMESTAMP DEFAULT NOW()
);

CREATE TABLE t_p29017774_avn_academy_training.student_elo (
  id SERIAL PRIMARY KEY,
  user_id INTEGER NOT NULL REFERENCES t_p29017774_avn_academy_training.users(id) ON DELETE CASCADE,
  subject VARCHAR(255) NOT NULL,
  elo_rating INTEGER NOT NULL DEFAULT 1000,
  updated_at TIMESTAMP DEFAULT NOW(),
  CONSTRAINT unique_user_subject UNIQUE (user_id, subject)
);

-- Индексы для оптимизации выборок
CREATE INDEX idx_test_questions_subject ON t_p29017774_avn_academy_training.test_questions(subject);
CREATE INDEX idx_test_attempts_user ON t_p29017774_avn_academy_training.test_attempts(user_id);
CREATE INDEX idx_test_answers_attempt ON t_p29017774_avn_academy_training.test_answers(attempt_id);

-- Вставка начального пула вопросов

-- 1. БАЗОВЫЙ УРОВЕНЬ (10 вопросов True/False или простой выбор)
INSERT INTO t_p29017774_avn_academy_training.test_questions (subject, type, question_text, options, correct_answer, explanation, elo_rating) VALUES
('Основы службы', 'choice', 'Разрешено ли курсанту покидать расположение части без увольнительного билета?', '["Да, до 2 часов", "Нет, категорически запрещено", "Только с устного согласия дежурного", "Да, в дневное время"]', '"Нет, категорически запрещено"', 'Выход за территорию части без увольнительного билета или предписания является самовольной отлучкой.', 800),
('Основы службы', 'choice', 'Какое звание является младшим офицерским?', '["Капитан", "Майор", "Младший лейтенант", "Старший сержант"]', '"Младший лейтенант"', 'Звание Младший лейтенант открывает линейку младших офицерских званий.', 900),
('Основы службы', 'choice', 'Является ли устный приказ командира обязательным к исполнению?', '["Да, безусловно", "Нет, только письменный приказ", "Только в военное время", "На усмотрение военнослужащего"]', '"Да, безусловно"', 'Приказ командира должен быть выполнен беспрекословно, точно и в срок.', 850),
('Огневая подготовка', 'choice', 'Калибр автомата АК-74 составляет 5.45 мм. Верно ли это утверждение?', '["Да, верно", "Нет, неверно"]', '"Да, верно"', 'Автомат АК-74 использует патроны калибра 5.45x39 мм.', 750),
('Огневая подготовка', 'choice', 'Допускается ли направление оружия на людей при проведении учебных тренировок без патронов?', '["Да", "Категорически запрещено", "Только по команде руководителя"]', '"Категорически запрещено"', 'Направление ствола оружия на людей запрещено в любых условиях, даже если оружие разряжено.', 800),
('Тактика', 'choice', 'Что означает сигнал "К бою" в тактическом перемещении?', '["Принять положение для стрельбы стоя", "Занять ближайшее укрытие и приготовиться к ведению огня", "Выстроиться в колонну", "Начать отступление"]', '"Занять ближайшее укрытие и приготовиться к ведению огня"', 'Сигнал требует немедленной изготовки к стрельбе из укрытия.', 900),
('Тактика', 'choice', 'Основным элементом боевого порядка взвода в наступлении является цепь. Верно?', '["Да", "Нет"]', '"Да"', 'В наступлении пехотное подразделение развертывается в цепь с интервалом между бойцами.', 850),
('Уставы', 'choice', 'Имеет ли право курсант обжаловать приказ до его выполнения?', '["Да", "Нет, сначала выполняется приказ, затем обжалуется", "Только коллективно", "Только через прокуратуру"]', '"Нет, сначала выполняется приказ, затем обжалуется"', 'Обжалование приказа возможно только после его выполнения.', 950),
('Уставы', 'choice', 'Кто является непосредственным начальником для командира отделения?', '["Командир взвода", "Начальник караула", "Командир роты", "Старшина роты"]', '"Командир взвода"', 'Командир взвода подчиняет командиров отделений напрямую.', 800),
('Физическая подготовка', 'choice', 'Является ли бег на 3 км обязательным нормативом физической подготовки?', '["Да", "Нет"]', '"Да"', 'Бег на 3000 метров является базовым тестом на выносливость военнослужащего.', 700);

-- 2. ПРОДВИНУТЫЙ УРОВЕНЬ (15 вопросов: множественный выбор и Drag-and-Drop)
-- Множественный выбор (multichoice)
INSERT INTO t_p29017774_avn_academy_training.test_questions (subject, type, question_text, options, correct_answer, explanation, elo_rating) VALUES
('Огневая подготовка', 'multichoice', 'Выберите все основные части автомата АК-74 из списка:', '["Ствол со ствольной коробкой", "Возвратный механизм", "Штык-нож", "Затворная рама с газовым поршнем", "Оптический прицел"]', '["Ствол со ствольной коробкой", "Возвратный механизм", "Затворная рама с газовым поршнем"]', 'Основные части включают ствол с коробкой, возвратный механизм, затворную раму с затвором.', 1200),
('Уставы', 'multichoice', 'Какие обязанности возложены на часового на посту?', '["Охранять и оборонять пост", "Спать на посту в отсутствие проверок", "Никому не отдавать оружие", "Покидать пост в случае дождя"]', '["Охранять и оборонять пост", "Никому не отдавать оружие"]', 'Часовой обязан охранять пост, быть бдительным и не передавать свое оружие третьим лицам.', 1150),
('Тактика', 'multichoice', 'Какие виды маневров используются отделениями в бою?', '["Обход", "Охват", "Смена дислокации", "Фронтальный удар"]', '["Обход", "Охват"]', 'Обход и охват — классические маневры тактических единиц.', 1300),
('Основы службы', 'multichoice', 'Какие меры дисциплинарного взыскания могут применяться к курсанту?', '["Выговор", "Лишение свободы", "Строгий выговор", "Наряд на службу вне очереди"]', '["Выговор", "Строгий выговор", "Наряд на службу вне очереди"]', 'Взыскания включают выговоры и наряды. Лишение свободы применяется только судом.', 1100),
('Физическая подготовка', 'multichoice', 'Какие упражнения входят в комплекс упражнений на силу?', '["Подтягивание на перекладине", "Сгибание-разгибание рук в упоре лежа", "Бег на 100 м", "Челночный бег"]', '["Подтягивание на перекладине", "Сгибание-разгибание рук в упоре лежа"]', 'Силовые упражнения — подтягивания и отжимания. Бег развивает выносливость и скорость.', 1050),
('Огневая подготовка', 'multichoice', 'Что необходимо проверить перед стрельбой?', '["Наличие патрона в патроннике", "Чистоту канала ствола", "Маркировку на прикладе", "Работу предохранителя"]', '["Наличие патрона в патроннике", "Чистоту канала ствола", "Работу предохранителя"]', 'Проверяется чистота ствола, отсутствие патрона и исправность предохранителя.', 1250);

-- Drag-and-drop сопоставление (matching)
INSERT INTO t_p29017774_avn_academy_training.test_questions (subject, type, question_text, options, correct_answer, explanation, elo_rating) VALUES
('Основы службы', 'matching', 'Сопоставьте погоны с воинскими званиями:', '{"pairs": {"Одна большая звезда": "Майор", "Две маленькие звезды": "Лейтенант", "Три маленькие звезды": "Старший лейтенант", "Четыре маленькие звезды": "Капитан"}}', '{"Одна большая звезда": "Майор", "Две маленькие звезды": "Лейтенант", "Три маленькие звезды": "Старший лейтенант", "Четыре маленькие звезды": "Капитан"}', 'Количество звезд определяет офицерское звание.', 1300),
('Огневая подготовка', 'matching', 'Сопоставьте тип оружия с его калибром:', '{"pairs": {"АК-74": "5.45 мм", "ПМ (Макаров)": "9 мм", "СВД": "7.62 мм", "РПГ-7": "40 мм"}}', '{"АК-74": "5.45 мм", "ПМ (Макаров)": "9 мм", "СВД": "7.62 мм", "РПГ-7": "40 мм"}', 'Калибры штатного стрелкового оружия ВС РФ.', 1200),
('Тактика', 'matching', 'Сопоставьте условное обозначение с его значением:', '{"pairs": {"Красный маркер": "Противник", "Синий маркер": "Свои силы", "Зеленый маркер": "Нейтральные объекты", "Желтый маркер": "Мины"}}', '{"Красный маркер": "Противник", "Синий маркер": "Свои силы", "Зеленый маркер": "Нейтральные объекты", "Желтый маркер": "Мины"}', 'Обозначения на тактических картах.', 1100),
('Уставы', 'matching', 'Сопоставьте обязанности должностных лиц:', '{"pairs": {"Дневальный": "Охрана внутренних помещений", "Дежурный по роте": "Контроль за дневальными", "Часовой": "Охрана внешнего поста", "Старшина": "Хозяйственное обеспечение"}}', '{"Дневальный": "Охрана внутренних помещений", "Дежурный по роте": "Контроль за дневальными", "Часовой": "Охрана внешнего поста", "Старшина": "Хозяйственное обеспечение"}', 'Разграничение обязанностей в суточном наряде.', 1250),
('Физическая подготовка', 'matching', 'Сопоставьте нормативы физической подготовки с оценкой "Отлично":', '{"pairs": {"Подтягивания": "15 раз", "Бег 100 м": "13.2 сек", "Бег 3 км": "12 мин 00 сек", "Кросс 5 км": "24 мин 00 сек"}}', '{"Подтягивания": "15 раз", "Бег 100 м": "13.2 сек", "Бег 3 км": "12 мин 00 сек", "Кросс 5 км": "24 мин 00 сек"}', 'Нормативы возрастной группы до 30 лет.', 1150);

-- Еще multichoice/matching для общего количества 15+
INSERT INTO t_p29017774_avn_academy_training.test_questions (subject, type, question_text, options, correct_answer, explanation, elo_rating) VALUES
('Тактика', 'multichoice', 'Какие действия входят в подготовку к маршу боевых машин?', '["Проверка ГСМ", "Установка спальных мест", "Маскировка техники", "Крепление личного состава ремнями безопасности"]', '["Проверка ГСМ", "Маскировка техники"]', 'Подготовка включает техническое обслуживание и маскировку.', 1350),
('Огневая подготовка', 'multichoice', 'Какие факторы влияют на траекторию полета пули?', '["Ветер", "Температура воздуха", "Сила тяжести", "Цвет мишени", "Вращение пули"]', '["Ветер", "Температура воздуха", "Сила тяжести", "Вращение пули"]', 'Физические факторы и гироскопический эффект влияют на баллистику.', 1400),
('Уставы', 'matching', 'Сопоставьте виды караулов с объектами охраны:', '{"pairs": {"Внутренний караул": "Склады боеприпасов роты", "Гарнизонный караул": "Объекты штаба гарнизона", "Временный караул": "Воинский эшелон в пути"}}', '{"Внутренний караул": "Склады боеприпасов роты", "Гарнизонный караул": "Объекты штаба гарнизона", "Временный караул": "Воинский эшелон в пути"}', 'Виды караульной службы регламентируются УГиКС.', 1300),
('Основы службы', 'multichoice', 'Какие категории граждан освобождаются от воинских сборов?', '["Студенты на время сессии", "Многодетные отцы (3+ детей)", "Государственные служащие", "Временно неработающие граждане"]', '["Студенты на время сессии", "Многодетные отцы (3+ детей)", "Государственные служащие"]', 'Освобождение регламентировано ФЗ "О воинской обязанности".', 1200);

-- 3. БОНУСНЫЙ УРОВЕНЬ (5 эссе-вопросов с критериями)
INSERT INTO t_p29017774_avn_academy_training.test_questions (subject, type, question_text, correct_answer, criteria_matrix, elo_rating) VALUES
('Тактика', 'essay', 'Опишите алгоритм действий отделения при попадании в огневую засаду противника на пересеченной местности.', '""', '{"criteria": ["Содержание и последовательность", "Использование складок местности", "Организация ответного огня", "Дисциплина связи", "Логика изложения"]}', 1600),
('Огневая подготовка', 'essay', 'Дайте развернутое объяснение явлению деривации при стрельбе из нарезного оружия на сверхдальние дистанции.', '""', '{"criteria": ["Определение деривации", "Физические основы вращения", "Влияние шага нарезов ствола", "Способы компенсации на прицеле", "Точность формулировок"]}', 1550),
('Уставы', 'essay', 'Раскройте понятие Единоначалия как ключевого принципа строительства Вооруженных Сил РФ. Каковы его границы и пределы ответственности?', '""', '{"criteria": ["Определение принципа", "Права и обязанности командира", "Пределы законности приказа", "Взаимосвязь с дисциплиной", "Качество аргументации"]}', 1500),
('Основы службы', 'essay', 'Проанализируйте психологические аспекты адаптации новобранцев в первые три месяца службы в воинском коллективе.', '""', '{"criteria": ["Выявление фаз адаптации", "Описание роли сержантского состава", "Предотвращение конфликтов", "Мотивационные факторы", "Структурность текста"]}', 1650),
('Тактика', 'essay', 'Разработайте схему форсирования водной преграды мотострелковым отделением при поддержке БМП-2 в условиях активного противодействия.', '""', '{"criteria": ["Расчет сил и средств", "Подготовка техники на плаву", "Порядок высадки десанта", "Действия при затоплении", "Тактическая обоснованность"]}', 1700);
